REQUEST_INPUT_TOOL = {
    "name": "request_input",
    "description": (
        "Request a specific piece of information from the human operator. "
        "Use when you need data you cannot derive from context: credentials, "
        "explicit file paths, forced-choice selections, or confirmation of "
        "irreversible actions. Always specify the type and explain why you need it."
    ),
    "input_schema": {
        "type": "object",
        "properties": {
            "input_type": {
                "type": "string",
                "enum": ["free_text", "choice", "confirmation", "credential", "file"],
            },
            "prompt": {
                "type": "string",
                "description": "What to ask the human. Be specific.",
            },
            "context": {
                "type": "string",
                "description": "Why you need this input (shown to the human).",
            },
            "options": {
                "type": "array",
                "items": {"type": "string"},
                "description": "Required for 'choice' type. List of valid answers.",
            },
            "default": {
                "description": "Value to use on timeout if not required.",
            },
            "required": {
                "type": "boolean",
                "default": True,
                "description": "If false, proceed with default on timeout.",
            },
            "timeout_sec": {
                "type": "number",
                "default": 300,
                "description": "Seconds to wait before timing out.",
            },
        },
        "required": ["input_type", "prompt"],
    },
}

async def handle_request_input(params: dict) -> str:
    req = InputRequest(
        input_type=InputType(params["input_type"]),
        prompt=params["prompt"],
        context=params.get("context", ""),
        options=params.get("options"),
        default=params.get("default"),
        required=params.get("required", True),
        timeout_sec=float(params.get("timeout_sec", 300)),
    )
    _requests[req.id] = req

    try:
        await asyncio.wait_for(req._event.wait(), timeout=req.timeout_sec)
        if req._error:
            return f"[INPUT ERROR] {req._error}"
        return _serialize_value(req.input_type, req._value)
    except asyncio.TimeoutError:
        if req.default is not None:
            return f"[TIMEOUT] No response. Using default: {req.default}"
        if not req.required:
            return "[TIMEOUT] No response. Skipping optional input."
        return "[TIMEOUT] Required input not received. Cannot proceed."
    finally:
        _requests.pop(req.id, None)

def _serialize_value(input_type: InputType, value: Any) -> str:
    if input_type == InputType.CREDENTIAL:
        # Never return the raw credential as a string to be logged
        # Instead, store it in a secure store and return a reference
        ref = _store_credential_securely(value)
        return f"credential_ref:{ref}"
    if input_type == InputType.CONFIRMATION:
        return "confirmed" if value else "denied"
    return str(value)

def _store_credential_securely(secret: str) -> str:
    import hashlib, secrets
    ref = secrets.token_hex(8)
    # In production: write to a secrets manager (Vault, AWS SSM, etc.)
    # Here: in-memory store (dev only)
    _credential_store[ref] = secret
    return ref

_credential_store: dict[str, str] = {}

def validate_input(req: InputRequest, raw_value: str) -> tuple[Any, str | None]:
    """
    Validate raw_value against the request's type and options.
    Returns (parsed_value, error_message). error_message is None on success.
    """
    if req.input_type == InputType.CHOICE:
        if req.options and raw_value not in req.options:
            return None, f"Invalid choice '{raw_value}'. Valid: {req.options}"
        return raw_value, None

    if req.input_type == InputType.CONFIRMATION:
        normalized = raw_value.strip().lower()
        if normalized in ("yes", "y", "true", "1", "confirm", "confirmed"):
            return True, None
        if normalized in ("no", "n", "false", "0", "deny", "denied"):
            return False, None
        return None, "Answer must be yes or no"

    if req.input_type == InputType.CREDENTIAL:
        if not raw_value.strip():
            return None, "Credential cannot be empty"
        return raw_value, None   # will be stored securely in _serialize_value

    if req.input_type == InputType.FILE:
        import os
        path = raw_value.strip()
        if not os.path.exists(path):
            return None, f"File not found: {path}"
        return path, None

    # FREE_TEXT
    if not raw_value and req.required:
        return None, "Response cannot be empty"
    return raw_value, None

from fastapi import FastAPI, HTTPException
from pydantic import BaseModel
from typing import Any

app = FastAPI()

class SubmitBody(BaseModel):
    value: Any

@app.get("/input-requests")
def list_input_requests():
    return [
        {
            "id":         r.id,
            "type":       r.input_type,
            "prompt":     r.prompt,
            "context":    r.context,
            "options":    r.options,
            "default":    r.default,
            "required":   r.required,
            "is_credential": r.input_type == InputType.CREDENTIAL,
        }
        for r in _requests.values()
    ]

@app.post("/input-requests/{request_id}/submit")
def submit_input(request_id: str, body: SubmitBody):
    req = _requests.get(request_id)
    if not req:
        raise HTTPException(404, "Request not found or already fulfilled")

    parsed, error = validate_input(req, str(body.value))
    if error:
        raise HTTPException(400, error)

    req._value = parsed
    req._event.set()
    return {
        "status": "submitted",
        "request_id": request_id,
        "type": req.input_type,
        # Do not echo credential values back
        "acknowledged": req.input_type != InputType.CREDENTIAL,
    }
